previewCss:
.darma-loader-heartbeat-pulse {
  display: inline-block;
  width: 50px;
  height: 50px;
  border-radius: 18px;
  background: var(--loader-color, #6366f1);
  transform: rotate(45deg);
  animation: darma-loader-heartbeat-pulse-heartbeat 1.05s ease-in-out infinite;
}
@keyframes darma-loader-heartbeat-pulse-heartbeat {
  0%, 100% { transform: rotate(45deg) scale(0.9); opacity: 0.7; }
  30% { transform: rotate(45deg) scale(1.05); opacity: 1; }
  45% { transform: rotate(45deg) scale(0.92); }
  60% { transform: rotate(45deg) scale(1.08); }
}

